solutions.javascript:
// Solution
function isValidCommitHash(hash) {
    if (hash.length !== 40) return false;
    for (let i = 0; i < hash.length; i++) {
        if (isNaN(parseInt(hash[i], 16))) return false;
    }
    return true;
}

solutions.python:
// Solution
class Solution:
    def is_valid_commit_hash(self, hash: str) -> bool:
        if len(hash) != 40:
            return False
        for char in hash:
            if char not in '0123456789ABCDEFabcdef':
                return False
        return True
